INSERT INTO `bot_knowledge` VALUES
('4','general_info','Aurora Hotel Plaza là khách sạn 4 sao tại TP. Biên Hòa, Đồng Nai. Địa chỉ: 253 Phạm Văn Thuận, KP 17, Phường Tam Hiệp, Tỉnh Đồng Nai. Hotline: 0251 3918 888. Email: info@aurorahotelplaza.com. Giờ check-in: 14:00. Giờ check-out: 12:00. Tổng 13 loại phòng và căn hộ (Deluxe, Premium, Studio, Suite, Apartment). Hồ bơi, Gym, Spa, Nhà hàng, Rooftop Bar, Phòng hội nghị miễn phí cho khách lưu trú (trừ dịch vụ). Bãi đỗ xe miễn phí. Phí dịch vụ 5% + VAT 8% đã bao gồm trong giá phòng.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('5','cancellation_policy','Chính sách hủy phòng: Hủy miễn phí trước 24 giờ so với giờ check-in. Hủy trong vòng 24 giờ hoặc không đến (no-show) bị tính phí tương đương 1 đêm đầu. Đặt trước tối đa 365 ngày. Lưu trú tối thiểu 1 đêm, tối đa 30 đêm. Early check-in hoặc Late check-out phụ thu 50.000 VND/lần.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('6','payment_method','Phương thức thanh toán: Tiền mặt VND, Chuyển khoản ngân hàng, Thanh toán trực tuyến qua cổng điện tử. Giá đã bao gồm 5% phí dịch vụ và 8% VAT. Điểm thành viên: 10.000 VND tiêu = 1 điểm. Điểm có hiệu lực 365 ngày.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('7','extra_guest_policy','Chính sách phụ thu khách ở thêm theo chiều cao: Dưới 1m = MIỄN PHÍ (bao gồm ăn sáng). Từ 1m đến 1m3 = 200.000 VND/đêm (bao gồm ăn sáng). Trên 1m3 và người lớn = 400.000 VND/đêm (bao gồm ăn sáng). Giường phụ thêm = 650.000 VND/đêm. Số khách tối đa phụ thuộc loại phòng.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('8','room_types_overview','Phân loại phòng: (A) PHÒNG KHÁCH SẠN — Deluxe (2 người, từ 1.600.000 VND/đêm), Premium Deluxe Double & Twin (2 người, từ 1.900.000 VND/đêm), Aurora Studio / VIP Suite (3 người, từ 2.300.000 VND/đêm). (B) CĂN HỘ — Modern & Indochine Studio (2 người, 1.850.000 VND), Modern & Classical Premium (3 người, 2.050.000 VND), Indochine & Classical & Family Apartment Family (5 người, 2.550.000 VND), Studio Apartment (2 người, 2.800.000 VND), Premium Apartment (3 người, 4.200.000 VND). Tất cả giá là giá cơ bản/đêm, giá cuối tuần và ngày lễ có thể cao hơn.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('9','services_overview','Dịch vụ khách sạn: MIỄN PHÍ — Phòng ốc 24/7, Dọn phòng hàng ngày, Hồ bơi & Gym. CÓ PHÍ — Massage trị liệu (500k/60 phút), Sauna & Jacuzzi (300k/45 phút), Nhà hàng Aurora (ăn sáng 200k, trưa/tối 350k, Set VIP 800k/người), Rooftop Bar (từ 150k/ly), Đưa đón sân bay (500k/chiều), Thuê xe tự lái (800k/ngày), Giặt ủi (50k/kg), Trông trẻ (100k/giờ), Tổ chức tiệc cưới (từ 15 triệu), Hội nghị (từ 6 triệu/nửa ngày), Văn phòng cho thuê (từ 3 triệu/tháng).','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('10','membership_overview','Chương trình thành viên Aurora: 4 hạng. (1) Thành Viên — tích điểm cơ bản (10.000 VND=1 điểm). (2) Bạc (từ 5.000 điểm) — giảm 5%, tích x1.5, check-in ưu tiên. (3) Vàng (từ 10.000 điểm) — giảm 10%, tích x2, late checkout 13h, 1 bữa sáng tặng. (4) Bạch Kim (từ 20.000 điểm) — giảm 15%, tích x3, early check-in 10h, late checkout 14h, nâng cấp phòng miễn phí, ăn sáng miễn phí mỗi ngày, ưu đãi Spa 20%.','2026-03-03 16:26:38','2026-03-03 16:26:38'),
('11','location_transport','Vị trí: Aurora Hotel Plaza tại 253 Phạm Văn Thuận, Phường Tam Hiệp, TP. Biên Hòa, Đồng Nai. Gần trung tâm thành phố Biên Hòa. Dịch vụ đưa đón sân bay Tân Sơn Nhất hoặc Long Thành theo yêu cầu, giá 500.000 VND/chiều, đặt trước 4 tiếng. Có bãi đỗ xe miễn phí cho ô tô và xe máy.','2026-03-03 16:26:38','2026-03-03 16:26:38');
