('293','54','0','bot','Dạ vâng, em xin lỗi vì sự cố vừa rồi. Có vẻ như hệ thống đang gặp một chút trục trặc nhỏ trong việc truy xuất thông tin phòng. Em đang cố gắng khắc phục ngay lập tức để anh/chị có thể đặt phòng.\n\nAnh/chị vui lòng đợi em một chút để em kiểm tra lại các loại phòng trung bình phù hợp với yêu cầu của mình nhé. Em sẽ phản hồi lại ngay khi có thông tin ạ.','text','0',NULL,'0',NULL,'2026-03-03 21:18:29'),
('294','55','22','customer','tôi muốn đặt phòng','text','0',NULL,'0',NULL,'2026-03-03 21:46:12'),
('295','55','0','bot','Chào mừng quý khách đến với Aurora Hotel Plaza!\n\nĐể em có thể giúp quý khách đặt phòng, xin vui lòng cung cấp các thông tin sau:\n*   **Ngày nhận phòng (Check-in date):**\n*   **Ngày trả phòng (Check-out date):**\n*   **Số lượng người lớn:**\n*   **Số lượng trẻ em (nếu có):**\n\nSau khi có thông tin này, em sẽ tìm các loại phòng phù hợp nhất và báo giá chi tiết cho quý khách ạ.','text','0',NULL,'0',NULL,'2026-03-03 21:46:14'),
('296','55','22','customer','ngày 4\\3 đén ngày 5\\3 với 2 ng','text','0',NULL,'0',NULL,'2026-03-03 21:46:46'),
('297','55','0','bot','Tuyệt vời! Quý khách muốn đặt phòng từ ngày 2024-03-04 đến ngày 2024-03-05 cho 2 người lớn.\n\nEm đã tìm thấy một số loại phòng phù hợp với yêu cầu của quý khách:\n\n*   **Deluxe:** Giá cơ bản 2.000.000 VND/đêm\n*   **Premium Deluxe Double:** Giá cơ bản 1.900.000 VND/đêm\n*   **Premium Deluxe Twin:** Giá cơ bản 1.900.000 VND/đêm\n*   **Aurora Studio:** Giá cơ bản 2.300.000 VND/đêm\n*   **Studio Apartment:** Giá cơ bản 2.800.000 VND/đêm\n*   **Modern Studio:** Giá cơ bản 1.850.000 VND/đêm\n*   **Indochine Studio:** Giá cơ bản 1.850.000 VND/đêm\n*   **Premium Apartment:** Giá cơ bản 2.200.000 VND/đêm\n*   **Modern Premium:** Giá cơ bản 2.050.000 VND/đêm\n*   **Classical Premium:** Giá cơ bản 2.050.000 VND/đêm\n*   **Family Apartment:** Giá cơ bản 2.550.000 VND/đêm\n*   **Indochine Family:** Giá cơ bản 2.550.000 VND/đêm\n*   **Classical Family:** Giá cơ bản 2.550.000 VND/đêm\n\nĐể em có thể tư vấn tốt nhất, quý khách có thể cho em biết về phân khúc giá mong muốn (Tiết kiệm/Trung cấp/Cao cấp) hoặc nhu cầu cụ thể của mình không ạ?','text','0',NULL,'0',NULL,'2026-03-03 21:47:02'),
('298','55','22','customer','TB','text','0',NULL,'0',NULL,'2026-03-03 21:47:14'),
('299','55','0','bot','Tuyệt vời! Với ngân sách \"Trung bình\", em xin gợi ý 3 lựa chọn phòng phù hợp nhất cho quý khách từ ngày 2024-03-04 đến 2024-03-05 cho 2 người lớn:\n\n*   **Premium Deluxe Double**\n    *   Giá: 1.900.000 VND/đêm\n    *   Tổng cộng cho 1 đêm: **1.900.000 VND**\n    *   [BOOK_NOW_BTN_SUCCESS: booking_code=BKA2603033EDA, booking_id=22]\n\n*   **Deluxe**\n    *   Giá: 2.000.000 VND/đêm\n    *   Tổng cộng cho 1 đêm: **2.000.000 VND**\n    *   [BOOK_NOW_BTN_SUCCESS: booking_code=BKA2603033EDA, booking_id=22]\n\n*   **Aurora Studio**\n    *   Giá: 2.300.000 VND/đêm\n    *   Tổng cộng cho 1 đêm: **2.300.000 VND**\n    *   [BOOK_NOW_BTN_SUCCESS: booking_code=BKA2603033EDA, booking_id=22]\n\nQuý khách vui lòng chọn phòng ưng ý nhất để tiến hành đặt phòng ạ!','text','0',NULL,'0',NULL,'2026-03-03 21:47:24'),
('300','55','22','customer','phòng dơ quá','text','0',NULL,'0',NULL,'2026-03-03 21:48:33'),
('301','55','0','bot','Tôi rất xin lỗi vì trải nghiệm không hài lòng của quý khách. Đây chắc chắn không phải là tiêu chuẩn dịch vụ mà Aurora Hotel Plaza mong muốn mang lại.\n\nEm đã gửi yêu cầu ưu tiên tới bộ phận liên quan để kiểm tra và xử lý ngay lập tức vấn đề phòng dơ. Nhân viên của chúng tôi sẽ liên hệ với quý khách trong thời gian sớm nhất để khắc phục tình hình.\n\nMột lần nữa, thành thật xin lỗi quý khách về sự bất tiện này.','text','0',NULL,'0',NULL,'2026-03-03 21:48:39'),
('302','55','22','customer','vòi nước bị tắt','text','0',NULL,'0',NULL,'2026-03-03 21:48:57'),
('303','55','0','bot','Tôi rất xin lỗi về sự cố vòi nước bị tắt, điều này chắc chắn gây ra sự bất tiện lớn cho quý khách.\n\nEm đã gửi yêu cầu ưu tiên tới bộ phận kỹ thuật để kiểm tra và xử lý ngay lập tức vấn đề này. Nhân viên của chúng tôi sẽ có mặt trong thời gian sớm nhất để khắc phục tình hình.\n\nMột lần nữa, thành thật xin lỗi quý khách về sự bất tiện này.','text','0',NULL,'0',NULL,'2026-03-03 21:49:03'),
('304','68','-243275646','customer','Chào bạn.','text','0',NULL,'0',NULL,'2026-03-03 22:17:11'),
('305','68','0','bot','Chào quý khách, tôi là AURORA - SIÊU AI QUẢN LÝ TỔNG của Aurora Hotel Plaza. Rất vui được hỗ trợ quý khách.\n\nQuý khách cần tôi giúp gì ạ?','text','0',NULL,'0',NULL,'2026-03-03 22:17:12'),
('306','68','-243275646','customer','bạn là ai, ai là kỹ sư cuẩ bạn','text','0',NULL,'0',NULL,'2026-03-03 22:17:47'),
('307','68','0','bot','Chào quý khách, tôi là AURORA - SIÊU AI QUẢN LÝ TỔNG của Aurora Hotel Plaza. Tôi được phát triển bởi Google để mang đến trải nghiệm tốt nhất cho quý khách.\n\nQuý khách cần tôi giúp gì ạ?','text','0',NULL,'0',NULL,'2026-03-03 22:17:49'),
('308','99','-1389258','customer','Chào','text','0',NULL,'0',NULL,'2026-03-04 08:04:07'),
('309','99','0','bot','Xin lỗi, hệ thống chưa được cấu hình khóa API (API Key) để Trợ lý ảo hoạt động. Quý khách vui lòng cấu hình tại config/api_keys.php','text','0',NULL,'0',NULL,'2026-03-04 08:04:07'),
('310','99','-1389258','customer','Chào','text','0',NULL,'0',NULL,'2026-03-04 08:08:40'),
('311','99','0','bot','Chào quý khách, tôi là Aurora, AI lễ tân của Aurora Hotel Plaza. Rất vui được hỗ trợ quý khách.\n\nĐể tôi có thể giúp quý khách tốt hơn, quý khách vui lòng cho tôi biết quý khách muốn tìm hiểu về dịch vụ nào, hoặc có câu hỏi cụ thể nào không ạ?','text','0',NULL,'0',NULL,'2026-03-04 08:08:43');
INSERT INTO `chat_quick_replies` VALUES
('1','general','/xin-chao','Chào mừng','Xin chào! Chào mừng Quý khách đến với Aurora Hotel Plaza. Em có thể hỗ trợ gì cho Quý khách hôm nay ạ?','1','1','7','2026-02-25 14:25:27'),
('2','general','/cam-on','Cảm ơn','Cảm ơn Quý khách đã liên hệ với Aurora Hotel Plaza. Chúc Quý khách một ngày tốt lành!','2','1','7','2026-02-25 14:25:27'),
('3','booking','/gia-phong','Hỏi về giá phòng','Quý khách có thể xem chi tiết giá phòng tại trang Phòng của chúng tôi, hoặc em có thể tư vấn trực tiếp. Quý khách dự định lưu trú từ ngày nào đến ngày nào ạ?','3','1','7','2026-02-25 14:25:27'),
('4','booking','/check-in','Giờ check-in/out','Giờ nhận phòng (Check-in) là 14:00 và giờ trả phòng (Check-out) là 12:00. Quý khách có thể đặt dịch vụ nhận phòng sớm hoặc trả phòng muộn với phụ phí nhỏ.','4','1','7','2026-02-25 14:25:27'),
('5','booking','/huy-phong','Chính sách hủy phòng','Đơn đặt phòng có thể hủy miễn phí trước 24 giờ so với giờ nhận phòng. Hủy trong vòng 24 giờ sẽ tính phí một đêm đầu tiên. Quý khách cần hỗ trợ hủy đặt phòng nào ạ?','5','1','7','2026-02-25 14:25:27'),
('6','payment','/thanh-toan','Phương thức thanh toán','Aurora Hotel Plaza chấp nhận thanh toán qua VNPay, tiền mặt và chuyển khoản ngân hàng. Quý khách cần hỗ trợ về thanh toán cụ thể nào ạ?','6','1','7','2026-02-25 14:25:27'),
('7','complaint','/xin-loi','Xin lỗi khách','Em xin thành thật xin lỗi Quý khách về sự bất tiện này. Em sẽ ngay lập tức chuyển phản hồi của Quý khách đến bộ phận phụ trách để được xử lý sớm nhất. Quý khách vui lòng để lại thông tin liên hệ để em theo dõi và phản hồi ạ.','7','1','7','2026-02-25 14:25:27'),
('8','general','/cho-doi','Yêu cầu chờ','Em đang kiểm tra thông tin cho Quý khách, vui lòng chờ em trong giây lát ạ (khoảng 1-2 phút). Em sẽ phản hồi ngay!','8','1','7','2026-02-25 14:25:27'),
('9','System','/dongchat','Kết thúc cuộc trò chuyện','Cảm ơn quý khách đã liên hệ với Aurora Hotel Plaza. Rất vui được hỗ trợ quý khách. Chúc quý khách một ngày tốt lành! [STOP_CHAT]','99','1',NULL,'2026-02-25 17:46:10');
