INSERT INTO `membership_tiers` VALUES
('1','Thành Viên','Member','0','0','0.00','Tích lũy điểm thưởng cho mỗi lần đặt phòng. 10.000 VND = 1 điểm. Điểm có hiệu lực 365 ngày.','Earn reward points for every booking. 10,000 VND = 1 point. Points valid for 365 days.','#94A3B8','fa-user','2026-03-03 16:26:38'),
('2','Bạc','Silver','1','5000','5.00','Giảm 5% tổng hóa đơn lưu trú. Tích điểm x1.5. Check-in ưu tiên. Quà tặng chào mừng khi nhận phòng.','5% discount on stay. 1.5x point earning. Priority check-in. Welcome gift.','#94A3B8','fa-medal','2026-03-03 16:26:38'),
('3','Vàng','Gold','2','10000','10.00','Giảm 10% tổng hóa đơn. Tích điểm x2. Late check-out đến 13:00 miễn phí. Đặt phòng ưu tiên. Complimentary breakfast 1 ngày.','10% discount. 2x points. Free late checkout to 13:00. Priority booking. 1 complimentary breakfast.','#F59E0B','fa-star','2026-03-03 16:26:38'),
('4','Bạch Kim','Platinum','3','20000','15.00','Giảm 15% tổng hóa đơn. Tích điểm x3. Late check-out đến 14:00. Early check-in từ 10:00. Nâng cấp phòng miễn phí (tùy availability). Bữa sáng miễn phí mỗi ngày. Ưu đãi Spa 20%. Đón tiếp riêng VIP.','15% discount. 3x points. Late checkout 14:00. Early check-in 10:00. Free room upgrade. Daily breakfast. 20% spa discount. VIP welcome.','#E2E8F0','fa-crown','2026-03-03 16:26:38');
