INSERT INTO `room_types` VALUES
('1','Deluxe','Deluxe Room','deluxe','room','instant','Phòng Deluxe rộng 35m² được thiết kế hiện đại với giường King size cao cấp, tầm nhìn thành phố tuyệt đẹp. Phòng được trang bị đầy đủ tiện nghi như TV màn hình phẳng, minibar, két an toàn và phòng tắm riêng với vòi sen massage. Đây là lựa chọn hoàn hảo cho cặp đôi hoặc khách công tác.','Luxurious room with panoramic view and exclusive services.','Không gian sang trọng với đầy đủ tiện nghi hiện đại','Luxury room with panoramic view','2','2','1','0','32.00','1 giường đôi lớn (1m8x2m)','WiFi miễn phí,TV màn hình phẳng,Minibar,Két an toàn,Điều hòa,Phòng tắm riêng,Vòi sen massage,Máy sấy tóc,Đồ vệ sinh cá nhân,Bàn làm việc,Điện thoại,Dép đi trong phòng,Áo choàng tắm','/assets/img/deluxe/deluxe-room-aurora-1.jpg,/assets/img/deluxe/deluxe-room-aurora-2.jpg,/assets/img/deluxe/deluxe-room-aurora-3.jpg','/assets/img/deluxe/deluxe-room-aurora-1.jpg','2000000.00','2200000.00','2500000.00','active','1','2025-11-19 00:31:03','2026-02-28 16:48:40','1900000.00','1400000.00','1600000.00','1100000.00','Dưới 4h và trả phòng trước 22h, không bao gồm bữa sáng','Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('2','Premium Deluxe Double','Deluxe Room','premium-deluxe','room','instant','Phòng Premium Deluxe 40m² mang đến trải nghiệm cao cấp hơn với không gian rộng rãi, giường King size sang trọng và khu vực tiếp khách riêng biệt. Phòng có tầm nhìn panorama tuyệt đẹp ra thành phố, được trang bị đầy đủ tiện nghi hiện đại bao gồm TV thông minh, hệ thống âm thanh cao cấp và phòng tắm với bồn tắm nằm.','Luxurious room with panoramic view and exclusive services.','Không gian cao cấp với tầm nhìn panorama tuyệt đẹp','Luxury room with panoramic view','2','2','1','0','48.00','1 giường đôi lớn (1m8x2m)','WiFi miễn phí,TV thông minh,Hệ thống âm thanh,Minibar cao cấp,Két an toàn,Điều hòa,Phòng tắm với bồn tắm,Vòi sen massage,Máy sấy tóc,Đồ vệ sinh cao cấp,Bàn làm việc,Khu vực tiếp khách,Máy pha cà phê,Áo choàng tắm cao cấp','/assets/img/premium-deluxe/premium-deluxe-aurora-hotel-1.jpg,/assets/img/premium-deluxe/premium-deluxe-aurora-hotel-2.jpg','/assets/img/premium-deluxe/premium-deluxe-aurora-hotel-1.jpg','1900000.00','3000000.00','3500000.00','active','2','2025-11-19 00:31:03','2025-12-21 18:17:07','2200000.00','1700000.00','1900000.00','1300000.00','Dưới 4h và trả phòng trước 22h, không bao gồm bữa sáng','Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('3','Premium Deluxe Twin',NULL,'premium-twin','room','instant','Phòng Premium Twin 38m² được thiết kế đặc biệt cho nhóm bạn hoặc gia đình nhỏ với 2 giường đơn cao cấp. Không gian hiện đại, thoáng đãng với đầy đủ tiện nghi như TV màn hình phẳng, minibar, két an toàn và phòng tắm riêng với vòi sen massage. Phòng có tầm nhìn đẹp ra thành phố.',NULL,'Lý tưởng cho nhóm bạn hoặc gia đình với 2 giường đơn',NULL,'2','2','2','1','48.00','2 giường đơn (1m4x2m)','WiFi miễn phí,TV màn hình phẳng,Minibar,Két an toàn,Điều hòa,Phòng tắm riêng,Vòi sen massage,Máy sấy tóc,Đồ vệ sinh cá nhân,Bàn làm việc,Điện thoại,Dép đi trong phòng,Áo choàng tắm','/assets/img/premium-twin/premium-deluxe-twin-aurora-1.jpg,/assets/img/premium-twin/premium-deluxe-twin-aurora-2.jpg','/assets/img/premium-twin/premium-deluxe-twin-aurora-1.jpg','1900000.00','2700000.00','3000000.00','active','3','2025-11-19 00:31:03','2025-12-21 18:17:07','2200000.00','1700000.00','1900000.00',NULL,NULL,'Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('4','Aurora Studio','Suite Room','vip-suite','room','instant','VIP Suite 60m² là đỉnh cao của sự sang trọng với phòng ngủ riêng biệt, phòng khách rộng rãi và phòng tắm cao cấp với bồn tắm Jacuzzi. Giường King size đặc biệt, tầm nhìn panorama 180 độ ra thành phố. Được trang bị đầy đủ tiện nghi 5 sao bao gồm TV thông minh, hệ thống âm thanh Bose, minibar cao cấp và dịch vụ butler 24/7.','Premium suite with separate living area and VIP services.','Đỉnh cao sang trọng với không gian riêng tư tuyệt đối','Premium suite with living area','3','2','2','1','54.00','1 giường siêu lớn (2mx2m)','WiFi miễn phí,TV thông minh 55 inch,Hệ thống âm thanh Bose,Minibar cao cấp,Két an toàn điện tử,Điều hòa thông minh,Phòng tắm với Jacuzzi,Vòi sen massage,Máy sấy tóc Dyson,Đồ vệ sinh Hermes,Bàn làm việc executive,Phòng khách riêng,Máy pha cà phê Nespresso,Áo choàng tắm cao cấp,Dịch vụ butler 24/7','/assets/img/vip/vip-room-aurora-hotel-1.jpg,/assets/img/vip/vip-room-aurora-hotel-3.jpg,/assets/img/vip/vip-room-aurora-hotel-4.jpg','/assets/img/vip/vip-room-aurora-hotel-1.jpg','2300000.00','5500000.00','6500000.00','active','4','2025-11-19 00:31:03','2025-12-21 18:17:07','2950000.00','2200000.00','2300000.00','1900000.00','Dưới 4h và trả phòng trước 22h, không bao gồm bữa sáng','Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('5','Studio Apartment','Studio Apartment','studio-apartment','apartment','inquiry','Căn hộ Studio 45m² được thiết kế thông minh với không gian mở, kết hợp phòng ngủ và phòng khách. Bếp nhỏ đầy đủ tiện nghi, giường Queen size thoải mái, khu vực làm việc riêng biệt. Lý tưởng cho khách lưu trú dài ngày hoặc cặp đôi muốn có không gian riêng tư.','Modern studio apartment with full kitchen and living space.','Không gian thông minh cho lưu trú dài ngày','Modern studio with kitchen','2','2','1','0','45.00','1 Giường Queen','WiFi miễn phí,TV thông minh,Bếp nhỏ đầy đủ,Tủ lạnh,Lò vi sóng,Ấm đun nước,Bàn ăn,Minibar,Két an toàn,Điều hòa,Máy giặt,Phòng tắm riêng,Vòi sen,Máy sấy tóc,Bàn làm việc,Sofa,Ban công','/assets/img/studio-apartment/can-ho-studio-aurora-hotel-1.jpg,/assets/img/studio-apartment/can-ho-studio-aurora-hotel-2.jpg','/assets/img/studio-apartment/can-ho-studio-aurora-hotel-1.jpg','2800000.00','3300000.00','3800000.00','active','11','2025-11-19 00:31:03','2025-12-18 21:44:35',NULL,NULL,NULL,NULL,NULL,'Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('6','Modern Studio','Studio Apartment','modern-studio','apartment','inquiry','Modern Studio 48m² với thiết kế hiện đại tối giản, nội thất cao cấp và hệ thống smart home. Không gian mở thoáng đãng, bếp hiện đại đầy đủ thiết bị, giường King size sang trọng. Tầm nhìn đẹp và ánh sáng tự nhiên tràn ngập.','Modern studio apartment with full kitchen and living space.','Thiết kế hiện đại với hệ thống smart home','Modern studio with kitchen','2','2','1','0','35.00','1 Giường King','WiFi miễn phí,TV thông minh,Smart home system,Bếp hiện đại,Tủ lạnh,Lò vi sóng,Máy rửa chén,Ấm đun nước,Bàn ăn,Minibar,Két an toàn,Điều hòa thông minh,Máy giặt,Phòng tắm cao cấp,Vòi sen massage,Máy sấy tóc,Bàn làm việc,Sofa cao cấp,Ban công rộng','/assets/img/modern-studio-apartment/modern-studio-apartment-1.jpg,/assets/img/modern-studio-apartment/modern-studio-apartment-2.jpg','/assets/img/modern-studio-apartment/modern-studio-apartment-1.jpg','1850000.00','3800000.00','4300000.00','active','5','2025-11-19 00:31:03','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố','1850000.00','2250000.00','12250000.00','15050000.00','1750000.00','2150000.00'),
('7','Indochine Studio','Studio Apartment','indochine-studio','apartment','inquiry','Indochine Studio 46m² mang phong cách Đông Dương độc đáo với nội thất gỗ tự nhiên, họa tiết truyền thống kết hợp hiện đại. Không gian ấm cúng, bếp đầy đủ tiện nghi, giường Queen size thoải mái. Lựa chọn hoàn hảo cho những ai yêu thích văn hóa Việt.','Modern studio apartment with full kitchen and living space.','Phong cách Đông Dương độc đáo và ấm cúng','Modern studio with kitchen','2','2','1','0','35.00','1 Giường Queen','WiFi miễn phí,TV màn hình phẳng,Bếp đầy đủ,Tủ lạnh,Lò vi sóng,Ấm đun nước,Bàn ăn,Minibar,Két an toàn,Điều hòa,Máy giặt,Phòng tắm,Vòi sen,Máy sấy tóc,Bàn làm việc,Sofa,Ban công,Trang trí Đông Dương','/assets/img/indochine-studio-apartment/indochine-studio-apartment-1.jpg,/assets/img/indochine-studio-apartment/indochine-studio-apartment-2.jpg','/assets/img/indochine-studio-apartment/indochine-studio-apartment-1.jpg','1850000.00','3500000.00','4000000.00','active','6','2025-11-19 00:31:03','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố','1850000.00','2250000.00','12250000.00','15050000.00','1750000.00','2150000.00'),
('8','Premium Apartment',NULL,'premium-apartment','apartment','inquiry','Premium Apartment 65m² với phòng ngủ riêng biệt, phòng khách rộng rãi và bếp đầy đủ tiện nghi cao cấp. Giường King size sang trọng, khu vực làm việc executive, phòng tắm với bồn tắm. Tầm nhìn đẹp ra thành phố, lý tưởng cho gia đình hoặc lưu trú dài hạn.',NULL,'Không gian cao cấp với phòng ngủ riêng biệt',NULL,'3','2','2','1','65.00','1 Giường King + Sofa bed','WiFi miễn phí,TV thông minh,Bếp cao cấp đầy đủ,Tủ lạnh lớn,Lò vi sóng,Máy rửa chén,Ấm đun nước,Bàn ăn 4 chỗ,Minibar,Két an toàn,Điều hòa,Máy giặt sấy,Phòng tắm với bồn tắm,Vòi sen massage,Máy sấy tóc,Bàn làm việc,Phòng khách riêng,Sofa cao cấp,Ban công lớn','/assets/img/premium-apartment/can-ho-premium-aurora-hotel-1.jpg,/assets/img/premium-apartment/can-ho-premium-aurora-hotel-2.jpg,/assets/img/premium-apartment/can-ho-premium-aurora-hotel-3.jpg','/assets/img/premium-apartment/can-ho-premium-aurora-hotel-1.jpg','2200000.00','5000000.00','5800000.00','active','12','2025-11-19 00:31:03','2026-03-02 08:56:37',NULL,NULL,NULL,NULL,NULL,'Thành phố',NULL,NULL,NULL,NULL,NULL,NULL),
('9','Modern Premium',NULL,'modern-premium','apartment','inquiry','Modern Premium 68m² với thiết kế hiện đại tối giản, nội thất cao cấp và công nghệ smart home tiên tiến. Phòng ngủ riêng với giường King size, phòng khách sang trọng, bếp hiện đại đầy đủ. Tầm nhìn panorama tuyệt đẹp.',NULL,'Hiện đại cao cấp với công nghệ smart home',NULL,'3','2','2','1','60.00','1 Giường King + Sofa bed','WiFi miễn phí,TV thông minh 55 inch,Smart home system,Bếp hiện đại cao cấp,Tủ lạnh lớn,Lò vi sóng,Máy rửa chén,Máy pha cà phê,Bàn ăn 4 chỗ,Minibar cao cấp,Két an toàn điện tử,Điều hòa thông minh,Máy giặt sấy,Phòng tắm cao cấp với bồn tắm,Vòi sen massage,Máy sấy tóc Dyson,Bàn làm việc executive,Phòng khách cao cấp,Sofa da,Ban công panorama','/assets/img/modern-premium-apartment/modern-premium-apartment-1.jpg,/assets/img/modern-premium-apartment/modern-premium-apartment-2.jpg','/assets/img/modern-premium-apartment/modern-premium-apartment-1.jpg','2050000.00','5700000.00','6500000.00','active','7','2025-11-19 00:31:03','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố','2050000.00','2450000.00','13650000.00','16450000.00','1950000.00','2350000.00'),
('10','Classical Premium',NULL,'classical-premium','apartment','inquiry','Classical Premium 66m² mang phong cách cổ điển sang trọng với nội thất gỗ tự nhiên cao cấp, họa tiết tinh tế. Phòng ngủ riêng, phòng khách ấm cúng, bếp đầy đủ tiện nghi. Không gian thanh lịch, quý phái cho những ai yêu thích sự cổ điển.',NULL,'Phong cách cổ điển sang trọng và thanh lịch',NULL,'3','2','2','1','60.00','1 Giường King + Sofa bed','WiFi miễn phí,TV màn hình phẳng,Bếp cao cấp,Tủ lạnh,Lò vi sóng,Ấm đun nước,Bàn ăn 4 chỗ,Minibar,Két an toàn,Điều hòa,Máy giặt,Phòng tắm với bồn tắm,Vòi sen,Máy sấy tóc,Bàn làm việc,Phòng khách,Sofa cổ điển,Ban công,Nội thất gỗ cao cấp','/assets/img/classical-premium-apartment/classical-premium-apartment-1.jpg,/assets/img/classical-premium-apartment/classical-premium-apartment-2.jpg','/assets/img/classical-premium-apartment/classical-premium-apartment-1.jpg','2050000.00','5300000.00','6000000.00','active','8','2025-11-19 00:31:03','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố','2050000.00','2450000.00','13650000.00','16450000.00','1950000.00','2350000.00'),
('11','Family Apartment',NULL,'family-apartment','apartment','inquiry','Family Apartment 75m² được thiết kế đặc biệt cho gia đình với 2 phòng ngủ riêng biệt, phòng khách rộng rãi và bếp đầy đủ. Phòng ngủ chính có giường King, phòng ngủ phụ có 2 giường đơn. Không gian thoải mái, an toàn cho trẻ em với đầy đủ tiện nghi hiện đại.',NULL,'Lý tưởng cho gia đình với 2 phòng ngủ riêng',NULL,'5','4','3','1','82.00','1 King + 2 Đơn','WiFi miễn phí,TV thông minh,Bếp đầy đủ,Tủ lạnh lớn,Lò vi sóng,Máy rửa chén,Ấm đun nước,Bàn ăn 6 chỗ,Minibar,Két an toàn,Điều hòa,Máy giặt sấy,2 Phòng tắm,Vòi sen,Máy sấy tóc,Bàn làm việc,Phòng khách rộng,Sofa,Ban công,Khu vực vui chơi trẻ em','/assets/img/family-apartment/can-ho-family-aurora-hotel-3.jpg,/assets/img/family-apartment/can-ho-family-aurora-hotel-5.jpg,/assets/img/family-apartment/can-ho-family-aurora-hotel-6.jpg','/assets/img/family-apartment/can-ho-family-aurora-hotel-3.jpg','2550000.00','6500000.00','7500000.00','active','13','2025-11-19 00:31:03','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố',NULL,'2550000.00',NULL,'17150000.00',NULL,'2450000.00'),
('12','Indochine Family',NULL,'indochine-family','apartment','inquiry','Indochine Family 72m² kết hợp phong cách Đông Dương truyền thống với tiện nghi hiện đại. 2 phòng ngủ riêng biệt, phòng khách ấm cúng với nội thất gỗ tự nhiên, bếp đầy đủ. Không gian văn hóa đậm chất Việt, lý tưởng cho gia đình yêu thích truyền thống.',NULL,'Phong cách Đông Dương cho gia đình',NULL,'5','4','3','1','82.00','1 King + 2 Đơn','WiFi miễn phí,TV màn hình phẳng,Bếp đầy đủ,Tủ lạnh,Lò vi sóng,Ấm đun nước,Bàn ăn 6 chỗ,Minibar,Két an toàn,Điều hòa,Máy giặt,2 Phòng tắm,Vòi sen,Máy sấy tóc,Bàn làm việc,Phòng khách,Sofa,Ban công,Nội thất Đông Dương,Trang trí truyền thống','/assets/img/indochine-family-apartment/indochine-family-apartment-1.jpg,/assets/img/indochine-family-apartment/indochine-family-apartment-2.jpg','/assets/img/indochine-family-apartment/indochine-family-apartment-1.jpg','2550000.00','6200000.00','7200000.00','active','9','2025-11-19 00:31:04','2025-12-21 18:17:07',NULL,NULL,NULL,NULL,NULL,'Thành phố',NULL,'2550000.00',NULL,'17150000.00',NULL,'2450000.00'),
('13','Classical Family',NULL,'classical-family','apartment','inquiry','Classical Family 78m² mang phong cách cổ điển sang trọng với 2 phòng ngủ rộng rãi, phòng khách thanh lịch và bếp cao cấp. Nội thất gỗ tự nhiên cao cấp, họa tiết tinh tế, không gian ấm cúng. Lựa chọn hoàn hảo cho gia đình yêu thích sự quý phái cổ điển.',NULL,'Sang trọng cổ điển cho gia đình',NULL,'5','4','3','1','82.00','1 King + 2 Đơn','WiFi miễn phí,TV màn hình phẳng,Bếp cao cấp đầy đủ,Tủ lạnh lớn,Lò vi sóng,Máy rửa chén,Ấm đun nước,Bàn ăn 6 chỗ,Minibar,Két an toàn,Điều hòa,Máy giặt sấy,2 Phòng tắm cao cấp,Vòi sen,Máy sấy tóc,Bàn làm việc,Phòng khách rộng,Sofa cổ điển,Ban công lớn,Nội thất gỗ cao cấp,Trang trí cổ điển','/assets/img/classical-family-apartment/classical-family-apartment1.jpg,/assets/img/classical-family-apartment/classical-family-apartment2.jpg','assets/img/classical-family-apartment/classical-family-apartment1.jpg','2550000.00','6800000.00','7800000.00','active','10','2025-11-19 00:31:04','2025-12-21 19:05:34',NULL,NULL,NULL,NULL,NULL,'Thành phố',NULL,'2550000.00',NULL,'17150000.00',NULL,'2450000.00');
