INSERT INTO `service_packages` VALUES
('1','1','Gói Cơ bản',NULL,'wedding-basic','Gói tiệc cưới cơ bản cho 200-300 khách.',NULL,'Sảnh tiệc 200-300 khách,Trang trí cơ bản,Menu 8 món,Âm thanh ánh sáng,Bàn ghế tiêu chuẩn,Backdrop sân khấu','15000000.00','VND','0','1','1','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('2','1','Gói Tiêu chuẩn',NULL,'wedding-standard','Gói tiệc cưới tiêu chuẩn cho 400-500 khách.',NULL,'Sảnh tiệc 400-500 khách,Trang trí theo chủ đề,Menu 10 món + tráng miệng,Âm thanh ánh sáng cao cấp,Bàn ghế VIP,Backdrop + Cổng hoa,MC chuyên nghiệp,Nhiếp ảnh cơ bản','25000000.00','VND','1','1','2','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('3','1','Gói VIP',NULL,'wedding-vip','Gói tiệc cưới VIP cho 600-800 khách.',NULL,'Sảnh tiệc 600-800 khách,Trang trí sang trọng,Menu 12 món + buffet tráng miệng,Âm thanh ánh sáng 3D,Bàn ghế VIP cao cấp,Backdrop + Cổng hoa + Sân khấu,MC + Ban nhạc,Nhiếp ảnh + Quay phim,Trang điểm cô dâu,Xe hoa','40000000.00','VND','1','1','3','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('4','3','Buffet Sáng',NULL,'restaurant-breakfast','Buffet sáng với hơn 50 món Á - Âu.',NULL,'Hơn 50 món ăn,Phở - Bún - Cháo,Bánh mì - Xúc xích,Trứng các loại,Hoa quả tươi,Nước ép - Cà phê,Thời gian: 6h-10h','200000.00','VND/người','0','1','1','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('5','3','Buffet Trưa/Tối',NULL,'restaurant-lunch-dinner','Buffet trưa hoặc tối với hơn 100 món.',NULL,'Hơn 100 món ăn,Hải sản tươi sống,Sushi Nhật Bản,BBQ Hàn Quốc,Món Việt truyền thống,Món Âu cao cấp,Tráng miệng đa dạng,Nước uống không giới hạn','350000.00','VND/người','1','1','2','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('6','3','Set Menu VIP',NULL,'restaurant-set-menu','Set menu cao cấp phục vụ riêng.',NULL,'Khai vị cao cấp,Súp đặc biệt,Món chính (Bò/Hải sản),Món phụ,Tráng miệng,Rượu vang,Phục vụ riêng tư,Không gian VIP','800000.00','VND/người','1','1','3','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('7','2','Gói Nửa ngày',NULL,'conference-half-day','Gói hội nghị nửa ngày (4 giờ) phù hợp cho 50-100 người.',NULL,'Phòng họp 50-100 người,Projector + Màn hình,Micro không dây,WiFi miễn phí,Coffee break 1 lần,Bảng Flipchart','6000000.00','VND/4 giờ','0','1','1','2025-11-19 01:34:50','2025-11-19 07:16:32'),
('8','2','Gói Cả ngày',NULL,'conference-full-day','Gói hội nghị cả ngày (8 giờ) cho 100-200 người.',NULL,'Phòng họp 100-200 người,Màn hình LED lớn,Hệ thống âm thanh cao cấp,WiFi tốc độ cao,Coffee break 2 lần,Buffet trưa,Bảng Flipchart + Bút,Hỗ trợ kỹ thuật','9000000.00','VND/8 giờ','1','1','2','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('9','2','Gói VIP',NULL,'conference-vip','Gói hội nghị VIP cho 200-300 người.',NULL,'Phòng hội nghị 200-300 người,Màn hình LED 3D,Âm thanh chuyên nghiệp,WiFi doanh nghiệp,Coffee break 3 lần,Buffet trưa + tối,Phòng VIP cho ban tổ chức,Ghi hình chuyên nghiệp,Hỗ trợ kỹ thuật 24/7','15000000.00','VND/ngày','1','1','3','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('10','4','Studio 20m²',NULL,'office-studio','Văn phòng Studio cho 2-3 người.',NULL,'Diện tích 20m²,2-3 người,Bàn làm việc,Ghế ergonomic,Tủ tài liệu,Điều hòa,WiFi 1Gbps','3000000.00','VND/tháng','0','1','1','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('11','4','Standard 40m²',NULL,'office-standard','Văn phòng Standard cho 5-8 người.',NULL,'Diện tích 40m²,5-8 người,Bàn làm việc,Ghế ergonomic,Tủ tài liệu,Điều hòa,WiFi 1Gbps,Phòng họp chung','5500000.00','VND/tháng','1','1','2','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('12','4','Premium 80m²',NULL,'office-premium','Văn phòng Premium cho 10-15 người.',NULL,'Diện tích 80m²,10-15 người,Bàn làm việc cao cấp,Ghế ergonomic,Tủ tài liệu,Điều hòa trung tâm,WiFi 1Gbps,Phòng họp riêng,Khu pantry riêng','8000000.00','VND/tháng','1','1','3','2025-11-19 01:34:50','2025-11-19 01:34:50');
INSERT INTO `services` VALUES
('1','Tổ chức tiệc cưới','Wedding Services','wedding-service','event','Aurora Hotel Plaza tự hào là địa điểm tổ chức tiệc cưới hàng đầu tại Đồng Nai với sảnh tiệc sang trọng 500m², sức chứa lên đến 800 khách. Đội ngũ chuyên nghiệp với hơn 500 tiệc cưới thành công.','Complete wedding planning and hosting services with elegant venues.','Sảnh tiệc 500m², sức chứa 800 khách, dịch vụ trọn gói','Elegant wedding venues and planning','celebration','0.00','Liên hệ','assets/img/post/wedding/tiec-cuoi-tai-aurora-1.jpg',NULL,'1','1','1','2025-11-19 01:34:50','2025-12-16 23:52:56'),
('2','Tổ chức hội nghị','Conference & Events','conference-service','event','Phòng hội nghị hiện đại với 5 phòng họp đa năng, sức chứa từ 20-300 người. Trang bị đầy đủ thiết bị hiện đại, WiFi tốc độ cao, dịch vụ coffee break và buffet.','Professional conference rooms and event spaces with full equipment.','Phòng họp hiện đại, thiết bị đầy đủ, WiFi tốc độ cao','Professional meeting spaces','meeting_room','5000000.00','VND','assets/img/service/meet/hoi-nghi-aurora-5.jpg',NULL,'1','1','2','2025-11-19 01:34:50','2025-12-21 15:21:41'),
('3','Nhà hàng Aurora','Aurora Restaurant','aurora-restaurant','restaurant','Nhà hàng sang trọng với sức chứa 200 khách, view thành phố tuyệt đẹp. Buffet đa dạng hơn 100 món Á-Âu: hải sản tươi sống, sushi Nhật Bản, BBQ Hàn Quốc, món Việt truyền thống.','Fine dining experience with Vietnamese and international cuisine.','Buffet 100+ món Á-Âu, view đẹp, đầu bếp 5 sao','Fine dining restaurant','restaurant','350000.00','VND/người','assets/img/restaurant/nha-hang-aurora-hotel-2.jpg',NULL,'1','1','3','2025-11-19 01:34:50','2025-12-21 15:21:27'),
('4','Văn phòng cho thuê','Office Rental','office-rental','other','Văn phòng hiện đại với 3 loại: Studio 20m², Standard 40m², Premium 80m². Đầy đủ nội thất, WiFi 1Gbps, phòng họp chung, bảo vệ 24/7.','Premium office spaces for rent with business amenities.','Văn phòng đầy đủ nội thất, WiFi 1Gbps, tiện ích đầy đủ','Premium office spaces','business_center','8000000.00','VND/tháng','assets/img/service/office/van-phong-cho-thue-aurora-2.jpg',NULL,'1','1','4','2025-11-19 01:34:50','2025-12-21 15:22:32'),
('5','Rooftop Bar',NULL,'rooftop-bar','restaurant','Quầy bar tầng thượng với view 360 độ thành phố Biên Hòa. Không gian sang trọng, âm nhạc sống mỗi tối thứ 6-7. Menu cocktail đa dạng.',NULL,'Bar tầng thượng, view 360°, cocktail đa dạng, nhạc sống',NULL,'local_bar','150000.00','VND/ly','assets/img/post/restaurant/rooftop-bar-1.jpg',NULL,'1','1','5','2025-11-19 01:34:50','2025-12-21 15:15:40'),
('6','Dịch vụ phòng 24/7',NULL,'room-service-24-7','room_service','Dịch vụ phòng hoạt động 24/7 với thực đơn đa dạng hơn 50 món.',NULL,'Gọi món ăn, đồ uống phục vụ tận phòng 24/7',NULL,'room_service','0.00','Miễn phí',NULL,NULL,'1','0','6','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('7','Dọn phòng hàng ngày',NULL,'daily-housekeeping','room_service','Dịch vụ dọn phòng hàng ngày với đội ngũ chuyên nghiệp.',NULL,'Dọn dẹp và thay đổi khăn giường mỗi ngày',NULL,'cleaning_services','0.00','Miễn phí',NULL,NULL,'1','0','7','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('8','Giặt ủi cao cấp',NULL,'laundry-service','laundry','Dịch vụ giặt ủi chuyên nghiệp với máy móc hiện đại.',NULL,'Giặt ủi quần áo chuyên nghiệp, giao nhận tận phòng',NULL,'local_laundry_service','50000.00','VND/kg',NULL,NULL,'1','0','8','2025-11-19 01:34:50','2025-11-19 01:34:50'),
('9','Massage trị liệu',NULL,'therapeutic-massage','spa','Massage trị liệu chuyên sâu giúp giảm căng thẳng, đau nhức cơ bắp.',NULL,'Massage thư giãn toàn thân với tinh dầu thiên nhiên',NULL,'spa','500000.00','VND/60 phút',NULL,NULL,'1','1','9','2025-11-19 01:34:50','2025-11-19 01:34:50'),
